<template>
	<view class="teamFans infocont">
		<view class="Tbox" :style="{
		
			background:'url('+$util.img('/statics/uni/img/team/bg.png')+') 0% 0% / 100% 100%  no-repeat',
			
		}">
			<view class="nav flex justify-between align-center">
				<view class="search flex justify-center align-center">
					<u-icon name="search"></u-icon>
					<input class="input" type="text" v-model="keyword" @confirm="search"
						placeholder-style="font-size:26rpx;color:#0000004d;" placeholder="请输入订单号或成员ID">
				</view>
			</view>
			<!-- <view class="label flex justify-center align-center">
				<text>我的团队</text>
			</view>
			<view class="fansNum flex justify-center align-center">
				<text class="skeleton-rect">
					{{fs_count}}
				</text>
			</view> -->
			<view class="teamNum flex align-center justify-center flex-direction">
				<view class="info flex align-center justify-center ">
					<view class="numBox flex align-center justify-center flex-direction ">
						<view class="num">{{fs_count}}
							<u-icon name="question-circle" color="#f00" style="margin-left: 10rpx;"
								@click="showmsg('包括直接邀请以及间接邀请的用户数量','团队总人数')" size="28"></u-icon>
						</view>
						<text class="title">团队总人数</text>
					</view>
					<view class="line"></view>
					<view class="numBox flex align-center justify-center flex-direction">

						<view class="num">{{today_order}}
							<u-icon name="question-circle" color="#f00" style="margin-left: 10rpx;"
								@click="showmsg('团队总用户今天产生的所有有效订单数','团队今日订单')" size="28"></u-icon>
						</view>
						<text class="title">团队今日订单</text>
					</view>
					<view class="line"></view>
					<view class="numBox flex align-center justify-center flex-direction">

						<view class="num">{{team_order}}
							<u-icon name="question-circle" color="#f00" style="margin-left: 10rpx;"
								@click="showmsg('团队总用户产生的所有有效订单数','团队总订单')" size="28"></u-icon>
						</view>
						<text class="title">团队总订单</text>
					</view>
				</view>
				<view class="row-line"></view>
				<view class="info flex align-center justify-center ">
					<view class="numBox flex align-center justify-center flex-direction">
						<view class="num">{{z_count}}
							<u-icon name="question-circle" color="#f00" style="margin-left: 10rpx;"
								@click="showmsg('直接邀请的用户数量','直推成员')" size="28"></u-icon>
						</view>
						<text class="title">直推成员</text>
					</view>
					<view class="line"></view>
					<view class="numBox flex align-center justify-center flex-direction">

						<view class="num">{{j_count}}
							<u-icon name="question-circle" color="#f00" style="margin-left: 10rpx;"
								@click="showmsg('非直接邀请的用户数量','间推成员')" size="28"></u-icon>
						</view>
						<text class="title">间推成员</text>
					</view>
					<view class="line"></view>
					<view class="numBox flex align-center justify-center flex-direction">

						<view class="num">{{y_count}}
							<u-icon name="question-circle" color="#f00" style="margin-left: 10rpx;"
								@click="showmsg('团队人数中已完成下单的用户数量','有效成员')" size="28"></u-icon>
						</view>
						<text class="title">有效成员</text>
					</view>
				</view>

			</view>

			<view class="wx flex justify-between align-center">
				<view class="tjr text-cut skeleton-rect">
					推荐人：{{pid>0?pid:'无'}}
				</view>
				<view  @click="copyText(userinfo.id+'')"  class="wxNum flex justify-end align-center skeleton-rect">
					<view class="text">
						ID：{{userinfo.id?userinfo.id:'无'}}
					</view>
					<image class="img" :src="$util.img(fz)" mode="aspectFit"></image>
				</view>
			</view>
			<view class="tg flex justify-between align-center">
				<view class="wxNum text-cut skeleton-rect"  @click="copyText(tg_link)">
					<text class="text">
						我的推广链接： 点击复制
					</text>
					<image class="img" :src="$util.img(fz)" mode="aspectFit"></image>
				</view>
				<view class="wxNum">
					<text class="" style="font-size: 14px;
    font-family: PingFangSC-Regular, PingFang SC;
    font-weight: 400;
    color: #fff;">
						累计佣金：{{parseFloat(total_money).toFixed(2)}}
					</text>
				</view>

			</view>

		</view>
		<view class="tab flex justify-around align-center solid-bottom">
			<view :class="sort5==1?'item tabActive':'item'" @click="search(5,1)">
				<view class="text skeleton-rect">
					直推成员
				</view>
			</view>
			<view :class="sort5==2?'item tabActive':'item'" @click="search(5,2)">
				<view class="text skeleton-rect">
					间推成员
				</view>
			</view>
			<view :class="sort5==3?'item tabActive':'item'" @click="search(5,3)">
				<view class="text skeleton-rect">
					推广订单
				</view>
			</view>
		</view>

		<view class="sort solid-bottom flex justify-around align-center bg-white" v-if="sort5 != 3">
			<view class="item flex align-center skeleton-rect" @click="search(1)">
				加入时间 <image class="img" :src="sort1==1 ?cddx:cxdd" mode="aspectFit"></image>
			</view>
			<view class="item flex align-center skeleton-rect" @click="search(2)">
				成员人数 <image class="img" :src="sort2==1 ?cddx:cxdd" mode="aspectFit"></image>
			</view>
			<view class="item flex align-center skeleton-rect" @click="search(3)">
				筛选 <image class="img" :src="$util.img(sx)" mode="aspectFit"></image>
			</view>
		</view>

		<view class="fansList">
			<!-- <view class="item" v-for="(item,index) in list" :key="index" @click="detail(item)">
						<view class="">
							<image :src="item.headurl_img" class="img" mode="aspectFit"></image>
						</view>
			</view> -->

			<view class="order" v-for="(order, orderindex) in list" :key="orderindex" v-if="sort5 != 3">


				<view class="item" @click="detail(order)">
					<view class="left">
						<image style="border-radius: 50%;" :src="order.headurl_img" mode="aspectFill"></image>
					</view>
					<view class="content">
						<view class="title u-line-2">{{ order.company }}({{order.id}})</view>
						<view class="type">级别：{{order.level_name}}</view>
						<view class="type">上级：{{order.pid}}</view>
						<view class="type">成员：{{order.team_count}}</view>


					</view>

				</view>



			</view>


			<view class="order" v-for="(order, orderindex) in list" :key="orderindex" v-if="sort5 == 3">
				<view class="top">
					<view class="left" @click="paste(order.ordersn)">

						<view class="store">{{ order.ordersn }}</view>
						<!-- <u-icon name="zhuanfa" size="30" color="rgb(94,94,94)"></u-icon> -->
						<image :src="copy" @click="copyText(order.ordersn)" style="width: 30rpx;height: 30rpx;"
							mode="aspectFit"></image>
						<!-- <u-icon name="arrow-right" color="rgb(203,203,203)" :size="26"></u-icon> -->
					</view>
					<view>成员：{{ order.uid1 }}</view>
				</view>
				<view class="item" @click="onGoods(order.goods_id)" style="margin-top: 20rpx;">
					<view class="left">
						<image :src="order.goods_img" mode="aspectFill"></image>
					</view>
					<view class="content">
						<view class="title u-line-2">{{ order.goods_name }}</view>
						<view class="type">{{ order._goods_type_text }}</view>

						<view class="delivery-time" style="color: #909399;">下单时间
							{{ $util.timeFormat(order.create_time,'yyyy-mm-dd hh:MM:ss') }}
						</view>
						<view class="type">成员级别：{{ order.level_name }}</view>

						<!-- 	<view class="delivery-time" v-if="order.status == 3">完成时间
							{{ $util.timeFormat(order.finish_time,'yyyy-mm-dd hh:MM:ss') }}
						</view> -->
						<view class="delivery-time " style="display: flex;
    justify-content: space-between;">

							<text class="total-price">
								合计: ￥{{parseFloat(order.total_price).toFixed(2)}}
							</text>
							<text>
								佣金: ￥<text
									style="color: red;font-weight: 600;">{{ parseFloat(order.commision_price).toFixed(2)}}</text>
							</text>
						</view>
					</view>
					<view class="right">
						<view class="price">
							￥{{ parseFloat(order.price).toFixed(2)}}
						</view>
						<view class="number">x{{ order.quantity }}</view>
					</view>

				</view>

				<!-- <view class="bottom"> -->
				<!-- <view class="more">
									<u-icon name="more-dot-fill" color="rgb(203,203,203)"></u-icon>
								</view> -->
				<!-- <view class="logistics btn">详情</view> -->

				<!-- <view class="evaluate btn" v-if="order.status == 0">立即支付</view> -->
				<!-- <view class="exchange btn" @click="$util.on('/pages/order/info?id='+order.id)">查看详情
					</view> -->

				<!-- </view> -->
			</view>
			<u-loadmore :status="loadStatus" icon-type="circle" v-if="list.length >0 && loaded" />
			<u-empty margin-top="100" v-if="loaded &&  list.length == 0"></u-empty>

			<!-- 	<view class="empty" style="margin-top: 80rpx;text-align: center;" v-if="loaded && list.length==0">
				<image :src="kong" mode="aspectFit"></image>
			</view> -->
		</view>

		<view class="dialog flex justify-center align-center" v-if="userShow">
			<view class="dialog-content" @click.stop="userShow =true">
				<image class="decorate-left" :src="team_details_img" mode="aspectFit"></image>
				<image class="decorate-right" :src="team_details_img" mode="aspectFit"></image>
				<view class="close-btn" @click.stop="userShow =false">
					<view class="close-btn-wrap">
						<u-icon class='icon' name="close-circle" color="#fff" size="48"></u-icon>
					</view>
				</view>

				<view class="user flex justify-start align-center">
					<image class="img" :src="user.headurl_img" mode="aspectFit"></image>
					<view class="nickname flex flex-direction justify-center align-start">
						<view class="name">
							{{user.company}}
						</view>
						<view class="time">
							加入时间：{{ $util.timeFormat(user.create_time,'yyyy-mm-dd hh:MM:ss') }}
						</view>
					</view>
				</view>
				<view class="detail">
					<view class="dBox flex justify-start align-center" @click="copyText(user.id)" >
						邀请码：{{user.id}}
						<image class="img" :src="$util.img(copy)" mode="aspectFit"></image>
					</view>
					<view class="dBox flex justify-start align-center">
						团队成员：{{user.team_count}}人
					</view>
					<view class="dBox flex justify-start align-center">
						自购订单：{{user.order_count}}单
					</view>
					<view class="dBox flex justify-start align-center">
						今日收益：{{user.today}}￥
					</view>
					<view class="dBox flex justify-start align-center">
						本月收益：{{user.month}}￥
					</view>
					<view class="dBox flex justify-start align-center">
						上月收益：{{user.last_month}}￥
					</view>
				</view>

			</view>
		</view>
		<u-modal v-model="hyyhShow" :show-title="false" @confirm="clickhyyh" @cancel="cancelhyyh" ref="showhyyh_box"
			:async-close="true" :show-cancel-button="true" :confirm-style="{
			color:'red',
			border:'2rpx solid #f4f5f8',
		}">


			<picker-view indicator-style="height:50px;" style="height: 332rpx;" :value="[sort3Index,sort4Index]"
				@change="bindChange" class="pickerView">
				<picker-view-column>
					<view class="item" style="height: 100rpx;" v-for="(item,index) in sort3List" :key="index">{{item}}
					</view>
				</picker-view-column>
				<picker-view-column>
					<view class="item" style="height: 100rpx;" v-for="(item,index) in sort4List" :key="index">{{item}}
					</view>
				</picker-view-column>

			</picker-view>
			<!-- <picker class="" mode="multiSelector" v-if="domainList.length>0" @change="changeDomain"
				@cancel="domainicon=true" @click="domainicon =false" :value="0" :range="domainList" range-key="value">


			</picker> -->
		</u-modal>

		<u-modal v-model="msgshow" :content="msgcontent" :title="msgtitle" :confirm-text="'我已了解'" :confirm-style="{
			color:'#000',
			fontWeight:600,
			border:'2rpx solid #f4f5f8',
		}"></u-modal>


	</view>
</template>

<script>
	export default {
		data() {
			return {
				msgshow: false,
				msgtitle: '',
				msgcontent: '',
				userShow: false,
				hyyhShow: false,
				bg: '/statics/uni/img/team/bg.png',
				cddx: '/statics/uni/img/team/cddx.png',
				cxdd: '/statics/uni/img/team/cxdd.png',
				kong: '/statics/uni/img/team/kong.png',
				sx: '/statics/uni/img/team/sx.png',
				fz: '/statics/uni/img/team/fz.png',
				copy: '/statics/uni/img/team/copy.png',
				fs_count: 0,
				team_order: 0,
				today_order: 0,
				y_count: 0,
				j_count: 0,
				z_count: 0,
				pid: 0,
				team_details_img: '',
				tg_link: '',
				total_money:'0.00',

				keyword: '',
				sort5: 1, //直推
				sort1: 1,
				sort2: 1,
				sort3: 0,
				sort4: 0,
				sort3Index: 0,

				sort3List: [
					'无',
					'7天内',
					'15天内',
					'30天内',
				],

				sort4List: [
					'无',
					'已出单',
					'未出单',
				],
				sort4Index: 0,

				// sort3List: [
				// 	[{
				// 		value: 1,
				// 		label: '7天内',
				// 	}, ],
				// 	[{
				// 		value: 1,
				// 		label: '7天内',
				// 	}, ],

				// ],

				pagesize: 10,


				loadStatus: 'loadmore',
				page: 1,

				count: 0,
				list: [],
				loaded: false,


				user: {
					id: '',
					company: '',
					headurl_img: '',
					pid: '',
					team_count: 0,
					order_count: 0,
					today: 0,
					month: 0,
					last_month: 0,
				}





			}
		},

		onReachBottom() {
			this.$nextTick(() => {
				if(this.loadStatus != 'loading')
					this.loadData()
			})
		},
		onLoad() {
			
			
			// if(this.userinfo.default_level == this.userinfo.level_id){
			// 	this.$util.msg('请先升级会员！')
			// 	setTimeout(()=>{
			// 			this.$util.back()
			// 	},1500)
			
			// }else{
				this.loadConfig();
				this.loadData();
			// }
		
		},
		methods: {
			showmsg(content, title) {
				this.msgcontent = content
				this.msgtitle = title
				this.msgshow = true
			},
			copyText(val) {
				
				uni.setClipboardData({
					data: val+"",
					success: function() {
						uni.showToast({
							title: '复制成功',
							mask: false,
							duration: 1500,
							icon: 'none'
						});
					},
				
				})
			},
			bindChange(e) {
				this.sort3 = e.detail.value[0]
				this.sort4 = e.detail.value[1]

				this.sort3Index = e.detail.value[0]
				this.sort4Index = e.detail.value[1]
			},

			clickhyyh() {
				this.$refs.showhyyh_box.clearLoading()
				this.hyyhShow = false


				this.search(4)


			},
			cancelhyyh() {
				this.sort3 = 0
				this.sort4 = 0
				this.sort3Index = 0
				this.sort4Index = 0
			},
			search(type, value) {


				if (type == 3) {
					this.hyyhShow = true;
					return;
				}
				// console.log(123);
				this.page = 1
				this.list = []
				this.loaded = false



				switch (type) {
					case 1: //加入时间



						if (this.sort1 == 1) {
							this.sort1 = 2
						} else {
							this.sort1 = 1
						}
						break;
					case 2: //成员人数

						if (this.sort2 == 1) {
							this.sort2 = 2
						} else {
							this.sort2 = 1
						}
						break;

					case 5:

						if (value) {
							this.sort5 = value
						} else {
							this.sort5 = 1
						}


						break;
					default:

				}

				this.loadData()
			},
			async loadData() {
				uni.showLoading({
					mask: true,
					title: '加载中...',

				})
				this.loadStatus = 'loading'
				await this.$u.api.team({
						keyword: this.keyword,
						sort1: this.sort1,
						sort2: this.sort2,
						sort3: this.sort3,
						sort4: this.sort4,
						sort5: this.sort5,
						page: this.page,
						pagesize: this.pagesize,
					})
					.then(res => {
						if (res.length == 0) {
							this.loadStatus = 'nomore'
						} else {
							if (this.list.length > 0) {
								this.list = this.list.concat(res)

							} else {
								this.list = res

							}

							if (res.length < this.pagesize) {
								this.loadStatus = 'nomore'
							} else {
								this.loadStatus = 'loadmore'
							}


							this.page++
						}
					}).catch(res => {})
				this.loaded = true;
				uni.hideLoading()
			},

			async loadConfig() {
				uni.showLoading({
					mask: true,
					title: '加载中...',

				})
				await this.$u.api.teamConfig()
					.then(res => {
						this.bg = res.bg
						this.cddx = res.cddx
						this.cxdd = res.cxdd
						this.kong = res.kong
						this.sx = res.sx
						this.fz = res.fz


						this.fs_count = res.fs_count
						this.team_order = res.team_order
						this.today_order = res.today_order
						this.y_count = res.y_count
						this.j_count = res.j_count
						this.z_count = res.z_count

						this.team_details_img = res.team_details_img
						this.pid = res.pid
						this.copy = res.copy
						this.tg_link = res.tg_link
						this.total_money = res.total_money


					}).catch(res => {})
				uni.hideLoading()
			},
			detail(item) {
				this.$u.api.teamUserDetail({
						id: item.id,
						pid: item.pid,
						sort5: this.sort5,
					})
					.then(res => {
						this.user = res

						this.userShow = true
					}).catch(res => {})
			}
		}
	}
</script>

<style lang="scss" scoped scoped>
	page {
		color: #303133;
		width: 100%;
		font-size: 28rpx;
		background-color: #f5f7fa;

		font-family: Helvetica Neue, Helvetica, sans-serif;
	}

	.teamFans {
		width: 100%;
		padding-bottom: 50rpx;
	}

	.infocont {
		min-height: 100vh;
		background: #f5f7fa;
	}

	.teamFans .Tbox {

		padding-bottom: 26rpx;
	}

	.teamFans .Tbox .nav {
		height: 88rpx;
		padding: 0 30rpx;
	}





	.justify-between {

		justify-content: space-between;
	}

	.align-center {

		align-items: center;
	}

	.flex {

		display: flex;
	}

	.justify-around {

		justify-content: space-around;
	}

	.justify-center {

		justify-content: center;
	}

	.justify-start {

		justify-content: flex-start;
	}

	.flex-direction {

		flex-direction: column;
	}




	.nav {
		white-space: nowrap;
	}

	.teamFans .Tbox .nav {
		height: 88rpx;
		padding: 0 30rpx;
	}

	.teamFans .Tbox .nav .search {
		width: 100%;
		height: 64rpx;
		background: #fff;
		border-radius: 8rpx;
		padding-left: 20rpx;
	}

	.teamFans .Tbox .label {
		padding-top: 44rpx;
		padding-bottom: 6rpx;
		text-align: center;
		font-size: 28rpx;
		font-family: PingFangSC-Regular, PingFang SC;
		font-weight: 400;
		color: #fff;
	}

	.teamFans .Tbox .fansNum {
		text-align: center;
		font-size: 72rpx;
		font-family: PingFangSC-Medium, PingFang SC;
		font-weight: 500;
		color: #fff;
	}

	.teamFans .Tbox .wx {
		padding: 40rpx 30rpx 2rpx;
	}

	.teamFans .Tbox .tg {
		padding: 20rpx 30rpx;
	}

	.teamFans .Tbox .tg .img {
		width: 28rpx;
		height: 28rpx;
		margin-left: 20rpx;
	}


	.teamFans .Tbox .tg .tjr {
		font-size: 28rpx;
		font-family: PingFangSC-Regular, PingFang SC;
		font-weight: 400;
		color: #fff;
	}

	.teamFans .Tbox .tg .wxNum .text {
		font-size: 30rpx;
		font-family: PingFangSC-Regular, PingFang SC;
		font-weight: 600;
		color: #fff;
